requirements.capl_script:
/* REQ_01 */
variables
{
  message BCM_Status_1 msgBCM;
  msTimer tCycle;
  const int CYCLE_MS = 100;
  int gHazardStatus = 0;
}

on start
{
  // Initialize message payload to safe state
  int i;
  for (i = 0; i < 8; i++)
  {
    msgBCM.byte(i) = 0;
  }
  msgBCM.dlc = 8;
  setTimer(tCycle, CYCLE_MS);
}

on timer tCycle
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    msgBCM.byte(i) = 0;
  }
  msgBCM.dlc = 8;
  msgBCM.Hazard_Light_Status = gHazardStatus;
  output(msgBCM);
  setTimer(tCycle, CYCLE_MS);
}

